# Example task: Write a package main HTTP handler that wires an http.ServeMux (standard library only, no third-party router) for GET /kv/{key} and PUT /kv/{key} backed by an in-memory store. Use the Go 1.22+ method+wildcard route patterns and r.PathValue. PUT returns 201 Created, GET returns the value (200) or 404 if absent. Expose newMux(s *Store) *http.ServeMux.
```go
package main

import (
	"io"
	"net/http"
	"sync"
)

type Store struct {
	mu sync.RWMutex
	m  map[string]string
}

func NewStore() *Store { return &Store{m: make(map[string]string)} }

func (s *Store) Get(key string) (string, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	v, ok := s.m[key]
	return v, ok
}

func (s *Store) Set(key, value string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.m[key] = value
}

// newMux wires routes with the Go 1.22+ method+wildcard ServeMux patterns —
// no third-party router. r.PathValue extracts the {key} segment.
func newMux(s *Store) *http.ServeMux {
	mux := http.NewServeMux()
	mux.HandleFunc("GET /kv/{key}", func(w http.ResponseWriter, r *http.Request) {
		v, ok := s.Get(r.PathValue("key"))
		if !ok {
			http.Error(w, "not found", http.StatusNotFound)
			return
		}
		w.Header().Set("Content-Type", "text/plain")
		io.WriteString(w, v)
	})
	mux.HandleFunc("PUT /kv/{key}", func(w http.ResponseWriter, r *http.Request) {
		body, err := io.ReadAll(r.Body)
		if err != nil {
			http.Error(w, "bad body", http.StatusBadRequest)
			return
		}
		s.Set(r.PathValue("key"), string(body))
		w.WriteHeader(http.StatusCreated)
	})
	return mux
}

func main() {
	http.ListenAndServe(":8080", newMux(NewStore()))
}
```
# Example task: Write an in-memory store package with sentinel errors ErrNotFound and ErrExists: Create returns ErrExists on a duplicate id, Get and Delete return ErrNotFound when the id is absent, List returns items sorted by id, using a concurrency-safe map.
```go
package store

import (
	"errors"
	"sort"
	"sync"
)

// Sentinel errors returned by the store; callers compare with errors.Is.
var (
	ErrNotFound = errors.New("not found")
	ErrExists   = errors.New("already exists")
)

// Task is the stored entity.
type Task struct {
	ID    string
	Title string
}

// MemStore is a concurrency-safe in-memory implementation of the store.
type MemStore struct {
	mu    sync.RWMutex
	tasks map[string]Task
}

// NewMemStore returns an initialised, empty store.
func NewMemStore() *MemStore {
	return &MemStore{tasks: make(map[string]Task)}
}

// Create inserts t, returning ErrExists if the ID is already present.
func (s *MemStore) Create(t Task) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.tasks[t.ID]; ok {
		return ErrExists
	}
	s.tasks[t.ID] = t
	return nil
}

// Get returns the task, or ErrNotFound if absent.
func (s *MemStore) Get(id string) (Task, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	t, ok := s.tasks[id]
	if !ok {
		return Task{}, ErrNotFound
	}
	return t, nil
}

// Delete removes the task, or returns ErrNotFound if absent.
func (s *MemStore) Delete(id string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.tasks[id]; !ok {
		return ErrNotFound
	}
	delete(s.tasks, id)
	return nil
}

// List returns all tasks sorted by ID.
func (s *MemStore) List() []Task {
	s.mu.RLock()
	defer s.mu.RUnlock()
	out := make([]Task, 0, len(s.tasks))
	for _, t := range s.tasks {
		out = append(out, t)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return out
}
```

